import { Link } from "react-router-dom";
import { useDocumentHead } from "../lib/useDocumentHead.js";
import { useRouteScrollContext } from "../lib/useRouteScrollContext.js";
import StubSection from "./StubSection.jsx";
import { SEO } from "../data/seo.js";
import { CASE_STUDIES } from "../data/caseStudies.js";
import { INDUSTRIES } from "../data/industries.js";
import { LINKS } from "../data/links.js";

// Work STUB. Owns: #case-studies and the W2 skyline showpiece mount
// [data-showpiece="skyline"] (9 industry agents, S11/S12). Proof route. The 9
// industry stats render here so facts_check sees all 9 site-wide. S07 composes
// the real horizontal case-study chapters + the extrude skyline.
export default function Work() {
  useDocumentHead(SEO["/work"]);
  // Route-scoped trigger context (scar #9) — S07 registers triggers via add().
  const { scopeRef } = useRouteScrollContext();

  return (
    <div ref={scopeRef}>
      <StubSection id="case-studies" eyebrow="Proof, not pitch" title="Case studies">
        <div className="grid gap-6 md:grid-cols-2">
          {CASE_STUDIES.map((c) => (
            <article key={c.title} className="rounded-md border border-line bg-surface p-6">
              <h3 className="font-display text-title font-semibold text-ink">{c.title}</h3>
              <p className="mt-3 font-body text-small text-ink-dim">{c.description}</p>
              <p className="mt-4 font-mono text-mono-trace text-muted">{c.agents}</p>
            </article>
          ))}
        </div>
      </StubSection>

      {/* W2 ★ industry-solutions skyline showpiece mount (S11/S12 fills). */}
      <StubSection
        id="industries"
        eyebrow="Nine industries"
        title="A drafted field of agents"
        mount="skyline"
      >
        <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
          {INDUSTRIES.map((a) => (
            <article key={a.industry} className="rounded-md border border-line bg-surface p-6">
              <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
                {a.industry}
              </p>
              <p className="mt-2 font-display text-title font-semibold text-accent">{a.stat}</p>
              <p className="mt-1 font-body text-small text-ink-dim">{a.subtitle}</p>
              <p className="mt-4 font-body text-small text-ink-dim">
                <span className="text-muted">Before:</span> {a.before}
              </p>
              <p className="mt-2 font-body text-small text-ink-dim">
                <span className="text-muted">Result:</span> {a.result}
              </p>
              <p className="mt-2 font-body text-small text-ink-dim">
                <span className="text-muted">After:</span> {a.after}
              </p>
            </article>
          ))}
        </div>
      </StubSection>

      {/* W3 recap CTA. */}
      <StubSection id="recap" eyebrow="Next step" title="Want this for your business?">
        <div className="flex flex-wrap gap-4">
          <a
            href={LINKS.calendly}
            target="_blank"
            rel="noopener noreferrer"
            className="rounded-sm bg-accent px-5 py-3 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
          >
            Book a call
          </a>
          <Link
            to="/contact"
            className="rounded-sm border border-line-2 px-5 py-3 font-body text-sm font-medium text-ink transition-colors hover:border-accent"
          >
            Contact us
          </Link>
        </div>
      </StubSection>
    </div>
  );
}

