/**
 * CountStrike — count-strike numbers (DIRECTION "CountStrike").
 *
 * The DOM ships the FINAL formatted value (SEO / no-JS safe). On the motion
 * tier a once ScrollTrigger (start "top 80%") rewinds the text to `from`, then
 * tweens a plain counter object to `to` over `duration` (EASE.SETTLE), writing
 * el.textContent = fmt(value) each frame from a cached element + cached
 * formatter (created once, never per frame). Holds forever (once:true).
 * Supersedes the legacy CountUp.jsx (left untouched/dead).
 *
 * Props:
 *   to        number  (required) target value.
 *   from      number  0          start value.
 *   decimals  number  0          fraction digits (min == max).
 *   prefix    string  ""         prepended to the formatted number.
 *   suffix    string  ""         appended to the formatted number.
 *   duration  number  DUR.SCENE  tween length (seconds).
 *   format    fn      —          optional n=>string override of the formatter.
 *   className string  ""         passthrough (caller adds font-mono as desired).
 *   as        string  "span"     rendered tag.
 *
 * Default formatter: en-IN grouping so 241800 → "2,41,800".
 * The accessible name is the element's real text (the DOM ships the final
 * formatted value; no aria-label — spans may not carry one, axe aria-prohibited-attr).
 * Root: data-count-strike, tabular-nums.
 *
 * Gate (scar #8): useMotionStatic() ⇒ final value stays as rendered,
 * data-static="true" + data-struck="true", zero GSAP.
 *
 * Reduced/mobile fallback: the final value (static tier above).
 *
 * Scars: #1 n/a (once:true, no synchronous kill in callbacks). #12 — the
 * `from` rewind + the trigger are created in the SAME context, so a trigger
 * that can't fire still leaves the final value in the DOM (it was rendered
 * there). onComplete writes the exact final string + data-struck (scar #13).
 * All GSAP inside the component's own gsap.context; cleanup reverts (StrictMode
 * idempotent — revert restores the DOM, the once trigger re-creates).
 */
import { useLayoutEffect, useMemo, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useMotionStatic } from "./useMotionStatic.js";
import { DUR, EASE } from "../../lib/motion.js";

gsap.registerPlugin(ScrollTrigger);

function CountStrike({
  to,
  from = 0,
  decimals = 0,
  prefix = "",
  suffix = "",
  duration = DUR.SCENE,
  format,
  className = "",
  as = "span",
}) {
  const isStatic = useMotionStatic();
  const rootRef = useRef(null);

  // Cached formatter — created once per prop change, never per frame.
  const fmt = useMemo(() => {
    if (format) return (n) => `${prefix}${format(n)}${suffix}`;
    return (n) =>
      `${prefix}${n.toLocaleString("en-IN", {
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals,
      })}${suffix}`;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [format, prefix, suffix, decimals]);

  const finalStr = fmt(to);

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const el = rootRef.current;
    if (!el) return undefined;

    const ctx = gsap.context(() => {
      // Rewind the SEO-rendered final value to `from` inside the same context
      // as the trigger (scar #12): if the trigger somehow never fires the
      // revert restores the final text.
      el.textContent = fmt(from);

      const counter = { value: from };
      gsap.to(counter, {
        value: to,
        duration,
        ease: EASE.SETTLE,
        scrollTrigger: {
          trigger: el,
          start: "top 80%",
          once: true,
        },
        onUpdate: () => {
          el.textContent = fmt(counter.value);
        },
        onComplete: () => {
          el.textContent = finalStr;
          el.setAttribute("data-struck", "true");
        },
      });
    }, rootRef);

    return () => ctx.revert();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isStatic, to, from, duration, fmt, finalStr]);

  const Tag = as;
  const cls = `tabular-nums ${className}`.trim();

  if (isStatic) {
    return (
      <Tag
        ref={rootRef}
        data-count-strike
        data-static="true"
        data-struck="true"
        className={cls}
      >
        {finalStr}
      </Tag>
    );
  }

  return (
    <Tag
      ref={rootRef}
      data-count-strike
      className={cls}
    >
      {finalStr}
    </Tag>
  );
}

export default CountStrike;
export { CountStrike };

