1	// verify.mjs — route-driven assertion suite (v0).
2	//
3	// Boots playwright-core against the running dev server (:5173) and asserts the
4	// invariants that must hold on every build. v0 targets the CURRENT single-page
5	// site; sprints extend ROUTES + add route-aware checks via the check() harness.
6	//
7	// Usage:
8	//   node scripts/qa/verify.mjs               full suite, all ROUTES
9	//   node scripts/qa/verify.mjs --route=/     restrict to one route
10	//   node scripts/qa/verify.mjs --skippreload pass ?skippreload to every load
11	//
12	// Exit 0 only if every check passes; non-zero with a failure list otherwise.
13	import fs from "fs";
14	import { chromium } from "playwright-core";
15	import { ROUTES, DEV_URL, resolveChrome, parseArgs } from "./routes.mjs";
16	
17	// axe-core source, injected per page for the a11y/contrast audit (WCAG 2 A+AA).
18	const AXE_SOURCE = fs.readFileSync(
19	  new URL("../../node_modules/axe-core/axe.min.js", import.meta.url),
20	  "utf8"
21	);
22	
23	const args = parseArgs();
24	const SKIP = args.skippreload ? "skippreload" : "";
25	const onlyRoute = args.route || null;
26	
27	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
28	
29	// ---- check() harness -------------------------------------------------------
30	const results = [];
31	function check(name, ok, info = "") {
32	  results.push({ name, ok: !!ok, info });
33	  console.log(`${ok ? "PASS" : "FAIL"} ${name}${info ? `  ${info}` : ""}`);
34	}
35	
36	// Any of these fetched while reduced-motion / mobile / a no-GL route is active
37	// is a chunk-gating leak (scar #10 + perf budget). Matches Vite dep-optimized
38	// paths and any future manual GL chunk names.
39	const GL_CHUNKS =
40	  /node_modules\/\.vite\/deps\/(three|@react-three|postprocessing)|node_modules\/(three|@react-three|postprocessing)|\b(three|drei|HeroCanvas|GLStage|webgl|PipelineScene|[A-Za-z]*Scene)[-.][\w]+\.js/i;
41	
42	// Draw-call measurement: composer passes are only counted with autoReset off,
43	// accumulated across ~10 ticks then averaged (autoReset-on reports just the
44	// final screen-quad pass == 1). Returns -1 when no GL context (window.__gl).
45	async function measureDrawCalls(page) {
46	  return page.evaluate(
47	    () =>
48	      new Promise((res) => {
49	        const gl = window.__gl;
50	        if (!gl) return res(-1);
51	        gl.info.autoReset = false;
52	        gl.info.reset();
53	        if (window.__frame) window.__frame.needsFrames = 30;
54	        let ticks = 0;
55	        const tick = () => {
56	          if (++ticks < 10) return requestAnimationFrame(tick);
57	          const avg = Math.round(gl.info.render.calls / ticks);
58	          gl.info.autoReset = true;
59	          res(avg);
60	        };
61	        requestAnimationFrame(tick);
62	      })
63	  );
64	}
65	
66	// ScrollTrigger count, or -1 when the page hasn't exposed window.__stCount yet
67	// (current site does not). Callers skip gracefully on -1.
68	function stCount(page) {
69	  return page.evaluate(() => (window.__stCount ? window.__stCount() : -1));
70	}
71	
72	const EXEC = await resolveChrome();
73	const browser = await chromium.launch({ executablePath: EXEC, headless: true });
74	
75	const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
76	// "/lab" is not a ROUTES entry (dev-only bench) — --route=/lab runs just the
77	// S04 lab suite below.
78	if (routes.length === 0 && onlyRoute !== "/lab") {
79	  console.error(`No ROUTES match --route=${onlyRoute}`);
80	  process.exit(2);
81	}
82	
83	for (const route of routes) {
84	  const url = DEV_URL + route.path + (SKIP ? (route.path.includes("?") ? "&" : "?") + SKIP : "");
85	
86	  // ---- DESKTOP pass: load clean, audit links/integrations, GL on showpiece --
87	  {
88	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
89	    const consoleErrors = [];
90	    const pageErrors = [];
91	    const requests = [];
92	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
93	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
94	    page.on("request", (r) => requests.push(r.url()));
95	
96	    let emailjsReq = null;
97	    await page.route("**/api.emailjs.com/**", (r) => {
98	      const req = r.request();
99	      // Keep the FULL post body — service/template ids live deep inside the
100	      // multipart form-data, well past any fixed slice. Slice only for display.
101	      emailjsReq = { url: req.url(), method: req.method(), post: req.postData() || "" };
102	      r.fulfill({ status: 200, body: "OK" });
103	    });
104	
105	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
106	    await sleep(3500);
107	
108	    const tag = `[${route.name}]`;
109	
110	    // Route mounts its OWN stub (not the catch-all NotFound, not another page).
