551	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
552	    const consoleErrors = [];
553	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 200)));
554	    await page.goto(DEV_URL + "/", { waitUntil: "load", timeout: 60000 });
555	
556	    let sawVeil = true;
557	    try {
558	      await page.waitForSelector("[data-preloader]", { timeout: 5000 });
559	    } catch {
560	      sawVeil = false;
561	    }
562	    check("[backbone] preloader veil shows on first load", sawVeil);
563	
564	    let veilGone = true;
565	    try {
566	      await page.waitForSelector("[data-preloader]", { state: "detached", timeout: 10000 });
567	    } catch {
568	      veilGone = false;
569	    }
570	    check("[backbone] preloader completes and unmounts", veilGone);
571	
572	    const post = await page.evaluate(() => ({
573	      done: window.__preloaderDone === true,
574	      unlocked: document.documentElement.style.overflow !== "hidden",
575	      scrollable: document.documentElement.scrollHeight > window.innerHeight,
576	    }));
577	    check("[backbone] preloaderDone fired after veil", post.done);
578	    check("[backbone] scroll unlocked after preloader", post.unlocked && post.scrollable,
579	      `(overflowUnlocked=${post.unlocked} scrollable=${post.scrollable})`);
580	
581	    // (b) Once per session: an in-app nav must NOT re-show it…
582	    await page.click('nav a[href="/work"]');
583	    await sleep(800);
584	    const reshownNav = await page.evaluate(() => !!document.querySelector("[data-preloader]"));
585	    check("[backbone] preloader NOT re-shown on in-app nav", !reshownNav);
586	    // …and neither must a same-session reload (sessionStorage gate).
587	    await page.reload({ waitUntil: "load" });
588	    await sleep(1200);
589	    const reshownReload = await page.evaluate(() => ({
590	      veil: !!document.querySelector("[data-preloader]"),
591	      done: window.__preloaderDone === true,
592	    }));
593	    check("[backbone] preloader NOT re-shown on same-session reload", !reshownReload.veil);
594	    check("[backbone] preloaderDone still fires when session-skipped", reshownReload.done);
595	    check("[backbone] preloader suite: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
596	    await page.close();
597	  }
598	
599	  // (c) ?skippreload bypass: no veil ever, preloaderDone still fires.
600	  {
601	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
602	    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
603	    await sleep(1000);
604	    const r = await page.evaluate(() => ({
605	      veil: !!document.querySelector("[data-preloader]"),
606	      done: window.__preloaderDone === true,
607	    }));
608	    check("[backbone] ?skippreload: no preloader node", !r.veil);
609	    check("[backbone] ?skippreload: preloaderDone still fired", r.done);
610	    await page.close();
611	  }
612	
613	  // (d) THE leak assertion (scar #9): 3 full /->work->studio->contact->/ SPA
614	  // cycles; __stCount() must return to the post-load baseline after each.
615	  {
616	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
617	    const pageErrors = [];
618	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 200)));
619	    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
620	    // Steady state: Home's in-view once-strikes (InkReveal/SplitLines) self-kill
621	    // on completion (~2s incl. delays) — measure AFTER, so the baseline and the
622	    // post-cycle counts sample the same lifecycle moment (S06).
623	    await sleep(2600);
624	
625	    const baseline = await stCount(page);
626	    check("[backbone] __stCount baseline > 0 (route sentinel alive)", baseline > 0, `(${baseline})`);
627	
628	    const CYCLE = ["/work", "/studio", "/contact", "/"];
629	    const counts = [];
630	    for (let cycle = 1; cycle <= 3; cycle++) {
631	      for (const path of CYCLE) {
632	        await page.click(`nav a[href="${path}"]`);
633	        await sleep(450);
634	      }
635	      await sleep(2300); // debounced refresh + once-strike self-kills settle
636	      counts.push(await stCount(page));
637	    }
638	    // S06 note: Home now carries once:true strike triggers that self-kill on a
639	    // lifecycle (not page-load) clock, so the count is steady-state-dependent.
640	    // The leak invariant: identical counts across identically-timed cycles (a
641	    // leak compounds per cycle) AND zero orphaned triggers (a leaked trigger
642	    // points at a detached element). Baseline equality was the stub-era check.
643	    check(
644	      "[backbone] zero trigger leak across 3 route cycles",
645	      counts[0] > 0 && counts.every((c) => c === counts[0]) && Math.abs(counts[0] - baseline) <= 3,
646	      `(baseline=${baseline} after cycles=${counts.join(",")})`
647	    );
648	    const orphans = await page.evaluate(() => (window.__stOrphans ? window.__stOrphans() : -1));
649	    check("[backbone] zero orphaned triggers after cycles (scar #9)", orphans === 0, `(${orphans})`);
650	    check("[backbone] leak suite: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
651	    await page.close();
652	  }
653	
654	  // (e) S05 chrome: nav links actually NAVIGATE (route changes + the new page
655	  // mounts through the transition seam), from both the navbar and the footer.
656	  {
657	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
658	    const pageErrors = [];
659	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 200)));
660	    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
661	    await sleep(1200);
662	
663	    await page.click('header nav a[href="/work"]');
664	    await sleep(900);
665	    const toWork = await page.evaluate(() => ({
666	      path: window.location.pathname,
667	      mounted: !!document.getElementById("case-studies"),
668	    }));
669	    check(
670	      "[chrome] navbar link navigates / -> /work (page mounts in seam)",
671	      toWork.path === "/work" && toWork.mounted,
672	      `(path=${toWork.path} mounted=${toWork.mounted})`
673	    );
674	
675	    await page.click('footer a[href="/studio"]');
676	    await sleep(900);
677	    const toStudio = await page.evaluate(() => ({
678	      path: window.location.pathname,
679	      mounted: !!document.getElementById("team"),
680	    }));
681	    check(
682	      "[chrome] footer link navigates /work -> /studio",
683	      toStudio.path === "/studio" && toStudio.mounted,
684	      `(path=${toStudio.path} mounted=${toStudio.mounted})`
685	    );
686	
687	    // Condense-on-scroll: shell-level trigger flips data-condensed and SURVIVES
688	    // navigation (it lives outside the per-route context — the scar-#9 trap).
689	    const condense = await page.evaluate(async () => {
690	      const header = document.querySelector("header[class*='sticky']") || document.querySelector("header");
691	      if (window.__lenis) window.__lenis.scrollTo(400, { immediate: true });
692	      else window.scrollTo(0, 400);
693	      await new Promise((r) => setTimeout(r, 500));
694	      const condensed = header?.hasAttribute("data-condensed");
695	      if (window.__lenis) window.__lenis.scrollTo(0, { immediate: true });
696	      else window.scrollTo(0, 0);
697	      await new Promise((r) => setTimeout(r, 500));
698	      const expanded = !header?.hasAttribute("data-condensed");
699	      return { condensed, expanded };
700	    });
701	    check(
702	      "[chrome] navbar condenses on scroll + survives navigation",
703	      condense.condensed && condense.expanded,
704	      `(condensed=${condense.condensed} re-expanded=${condense.expanded})`
705	    );
706	    check("[chrome] nav suite: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
707	    await page.close();
708	  }
709	}
710	
711	// ---- S04 lab suite: motion primitive proof bench (/lab, DEV-only) ----------
712	// /lab mounts every v2 primitive once (src/pages/Lab.jsx). Asserted per tier:
713	// desktop = motion tier (strikes fire, pins exist, latches commit), reduced +
714	// mobile = designed static finals (scar #8). The route only exists on the dev
715	// server — the prod build DCEs it out (checked separately via the build grep).
716	const LAB_BLOCKS = [
717	  "split-lines", "ink-reveal", "draft-line", "dimension-mark", "snap-stack",
718	  "axis-rail", "kinetic-marquee", "magnetic-button", "magnetic-cursor",
719	  "count-strike", "scrub-scene", "parallax-layer", "chapter-marker", "section",
720	];
721	const labWalk = async (page, steps = 12, settle = 650) => {
722	  for (let i = 1; i <= steps; i++) {
723	    await page.evaluate((f) => {
724	      const max = document.documentElement.scrollHeight - window.innerHeight;
725	      const y = Math.round(max * f);
726	      if (window.__lenis) window.__lenis.scrollTo(y, { immediate: true });
727	      else window.scrollTo(0, y);
728	    }, i / steps);
729	    await sleep(settle);
730	  }
731	};
732	if (!onlyRoute || onlyRoute === "/lab") {
733	  const labUrl = DEV_URL + "/lab?skippreload";
734	
735	  // (a) DESKTOP — motion tier: everything mounts, strikes fire, latches commit.
736	  {
737	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
738	    const consoleErrors = [];
739	    const pageErrors = [];
740	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
741	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
742	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
743	    await sleep(2500); // fonts.ready + split/measure + first triggers
744	
745	    const missing = await page.evaluate(
746	      (names) => names.filter((n) => !document.querySelector(`[data-lab="${n}"]`)),
747	      LAB_BLOCKS
748	    );
749	    check(
750	      "[lab] all 14 primitive blocks mount",
751	      missing.length === 0,
752	      missing.length ? `missing: ${missing.join(",")}` : ""
753	    );
754	
755	    const tier = await page.evaluate(() => ({
756	      statics: document.querySelectorAll('[data-lab] [data-static="true"], [data-lab][data-static="true"]').length,
757	      pinSpacers: document.querySelectorAll(".pin-spacer").length,
758	      cursor: !!document.querySelector("[data-magnetic-cursor]"),
759	    }));
760	    check("[lab] desktop: motion tier active (zero static fallbacks)", tier.statics === 0, `(${tier.statics})`);
761	    check("[lab] desktop: pinned scenes mounted (axis-rail + scrub-scene)", tier.pinSpacers >= 2, `(${tier.pinSpacers} pin-spacers)`);
762	    check("[lab] desktop: magnetic cursor mounted", tier.cursor);
763	
764	    await labWalk(page);
765	    await sleep(900);
766	
767	    const settled = await page.evaluate(() => {
768	      const ink = document.querySelector('[data-lab="ink-reveal"] [data-ink-reveal]');
769	      const split = document.querySelector('[data-lab="split-lines"] [data-split-lines]');
770	      const counts = [...document.querySelectorAll("[data-count-strike]")].map((e) => e.textContent.trim());
771	      const rail = document.querySelector("[data-axis-rail]");
772	      return {
773	        inkRevealed: ink?.getAttribute("data-revealed") === "true",
774	        inkOpacity: ink ? getComputedStyle(ink).opacity : "missing",
775	        splitDone: split?.getAttribute("data-split") === "done",
776	        splitText: (split?.closest('[data-lab="split-lines"]')?.innerText || "")
777	          .replace(/\s+/g, " ")
778	          .includes("Blueprints resolve into built reality"),
779	        counts,
780	        readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
781	        railLatched: rail?.getAttribute("data-latched") || "(none)",
782	      };
783	    });
784	    check(
785	      "[lab] InkReveal struck + holds (opacity 1)",
786	      settled.inkRevealed && settled.inkOpacity === "1",
787	      `(revealed=${settled.inkRevealed} opacity=${settled.inkOpacity})`
788	    );
789	    check(
790	      "[lab] SplitLines revealed, text intact",
791	      settled.splitDone && settled.splitText,
792	      `(done=${settled.splitDone} textOk=${settled.splitText})`
793	    );
794	    check("[lab] CountStrike ₹2,41,800 committed", settled.counts.some((t) => t.includes("2,41,800")), `(${settled.counts.join(" | ")})`);
795	    check("[lab] CountStrike 99.3% committed", settled.counts.some((t) => t.includes("99.3")), `(${settled.counts.join(" | ")})`);
796	    check("[lab] ScrubScene progress committed to 1.000", settled.readout === "1.000", `(${settled.readout})`);
797	    check("[lab] AxisRail latched end state (scar #5)", settled.railLatched === "end", `(${settled.railLatched})`);
798	
799	    // Fling commit (scar #5): hard top, then one immediate jump past everything —
800	    // latches must still land the end states, nothing strands mid-scrub.
801	    await page.evaluate(() => (window.__lenis ? window.__lenis.scrollTo(0, { immediate: true }) : window.scrollTo(0, 0)));
802	    await sleep(500);
803	    await page.evaluate(() => {
804	      const max = document.documentElement.scrollHeight - window.innerHeight;
805	      if (window.__lenis) window.__lenis.scrollTo(max, { immediate: true });
806	      else window.scrollTo(0, max);
807	    });
808	    await sleep(1400);
809	    const flung = await page.evaluate(() => ({
810	      readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
811	      railLatched: document.querySelector("[data-axis-rail]")?.getAttribute("data-latched"),
812	    }));
813	    check(
814	      "[lab] fling commits end states (scar #5 latch)",
815	      flung.readout === "1.000" && flung.railLatched === "end",
816	      `(readout=${flung.readout} rail=${flung.railLatched})`
817	    );
818	
819	    // Scar #9: every lab trigger dies on route-leave.
820	    const labCount = await stCount(page);
821	    check("[lab] __stCount > 0 on /lab", labCount > 0, `(${labCount})`);
822	    await page.click('nav a[href="/"]');
823	    await sleep(900);
824	    // Home now carries its own rich trigger set (S06), so "home < lab" no
825	    // longer proves anything. The orphan detector does: any lab trigger that
826	    // survived the route-leave points at a detached element.
827	    const afterLeave = await page.evaluate(() => ({
828	      count: window.__stCount ? window.__stCount() : -1,
829	      orphans: window.__stOrphans ? window.__stOrphans() : -1,
830	    }));
831	    check(
832	      "[lab] lab triggers die on route-leave (scar #9)",
833	      afterLeave.count >= 1 && afterLeave.orphans === 0,
834	      `(lab=${labCount} home=${afterLeave.count} orphans=${afterLeave.orphans})`
835	    );
836	
837	    check("[lab] desktop: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
838	    check("[lab] desktop: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
839	
840	    // axe (WCAG 2 A+AA) on the bench too — dev-only is no excuse for bad contrast.
841	    try {
842	      await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
843	      await sleep(2000);
844	      await page.addScriptTag({ content: AXE_SOURCE });
845	      const axe = await page.evaluate(async () => {
846	        const res = await window.axe.run(document, {
847	          runOnly: { type: "tag", values: ["wcag2a", "wcag2aa"] },
848	          resultTypes: ["violations"],
849	        });
850	        return res.violations.map((v) => ({ id: v.id, impact: v.impact, nodes: v.nodes.length, help: v.help }));
851	      });
852	      const blocking = axe.filter((v) => v.impact === "critical" || v.impact === "serious");
853	      check(
854	        "[lab] axe: no serious/critical violations",
855	        blocking.length === 0,
856	        blocking[0] ? `${blocking[0].id} x${blocking[0].nodes} — ${blocking[0].help}`.slice(0, 120) : ""
857	      );
858	    } catch (e) {
859	      check("[lab] axe audit ran", false, String(e).slice(0, 120));
860	    }
861	    await page.close();
862	  }
863	
864	  // (b) REDUCED-MOTION — designed static finals, no pins, no GL, no cursor.
865	  {
866	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 }, reducedMotion: "reduce" });
867	    const consoleErrors = [];
868	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
869	    const requests = [];
870	    page.on("request", (r) => requests.push(r.url()));
871	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
872	    await sleep(2500);
873	
874	    const r = await page.evaluate((names) => {
875	      const blocksWithStatic = names.filter((n) => {
876	        const w = document.querySelector(`[data-lab="${n}"]`);
877	        return w && (w.matches('[data-static="true"]') || w.querySelector('[data-static="true"]'));
878	      });
879	      const split = document.querySelector('[data-lab="split-lines"]');
880	      const ink = document.querySelector('[data-lab="ink-reveal"] [data-ink-reveal], [data-lab="ink-reveal"] [data-static]');
881	      return {
882	        blocksWithStatic: blocksWithStatic.length,
883	        pinSpacers: document.querySelectorAll(".pin-spacer").length,
884	        cursor: !!document.querySelector("[data-magnetic-cursor]"),
885	        splitText: (split?.innerText || "").replace(/\s+/g, " ").includes("Blueprints resolve into built reality"),
886	        inkVisible: ink ? getComputedStyle(ink).opacity === "1" : false,
887	        counts: [...document.querySelectorAll("[data-count-strike]")].map((e) => e.textContent.trim()),
888	        readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
889	        hasText: document.body.innerText.trim().length > 400,
890	      };
891	    }, LAB_BLOCKS);
892	    check("[lab] reduced: static fallbacks rendered (>= 11 blocks)", r.blocksWithStatic >= 11, `(${r.blocksWithStatic})`);
893	    check("[lab] reduced: zero pins", r.pinSpacers === 0, `(${r.pinSpacers})`);
894	    check("[lab] reduced: no custom cursor", !r.cursor);
895	    check("[lab] reduced: SplitLines static text fully readable", r.splitText);
896	    check("[lab] reduced: InkReveal final state visible", r.inkVisible);
897	    check(
898	      "[lab] reduced: CountStrike shows final numbers immediately",
899	      r.counts.some((t) => t.includes("2,41,800")) && r.counts.some((t) => t.includes("99.3")),
900	      `(${r.counts.join(" | ")})`
901	    );
902	    check("[lab] reduced: ScrubScene reports final progress 1.000", r.readout === "1.000", `(${r.readout})`);
903	    check("[lab] reduced: content present (not blank)", r.hasText);
904	    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
905	    check("[lab] reduced: zero GL chunks fetched", leaked.length === 0, leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : "");
906	    check("[lab] reduced: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
907	    await page.close();
908	  }
909	
910	  // (c) MOBILE 390px — static tier + zero horizontal overflow.
911	  {
912	    const page = await browser.newPage({ viewport: { width: 390, height: 844 }, hasTouch: true });
913	    const consoleErrors = [];
914	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
915	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
916	    await sleep(2500);
917	    const m = await page.evaluate((names) => ({
918	      missing: names.filter((n) => !document.querySelector(`[data-lab="${n}"]`)).length,
919	      overflowOk: document.documentElement.scrollWidth <= window.innerWidth + 1,
920	      pinSpacers: document.querySelectorAll(".pin-spacer").length,
921	      cursor: !!document.querySelector("[data-magnetic-cursor]"),
922	      counts: [...document.querySelectorAll("[data-count-strike]")].map((e) => e.textContent.trim()),
923	      hasText: document.body.innerText.trim().length > 400,
924	    }), LAB_BLOCKS);
925	    check("[lab] mobile: all blocks mount", m.missing === 0, `(${m.missing} missing)`);
926	    check("[lab] mobile: no horizontal overflow at 390px", m.overflowOk);
927	    check("[lab] mobile: zero pins", m.pinSpacers === 0, `(${m.pinSpacers})`);
928	    check("[lab] mobile: no custom cursor (coarse pointer)", !m.cursor);
929	    check(
930	      "[lab] mobile: CountStrike final numbers immediate",
931	      m.counts.some((t) => t.includes("2,41,800")),
932	      `(${m.counts.join(" | ")})`
933	    );
934	    check("[lab] mobile: content present", m.hasText);
935	    check("[lab] mobile: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
936	    await page.close();
937	  }
938	}
939	
940	await browser.close();
941	
942	const fails = results.filter((r) => !r.ok);
943	console.log(`\n${results.length - fails.length}/${results.length} checks passed`);
944	if (fails.length) {
945	  console.log("\nFAILURES:");
946	  for (const f of fails) console.log(`  - ${f.name}${f.info ? `  ${f.info}` : ""}`);
947	}
948	process.exit(fails.length ? 1 : 0);
