import { chromium } from "playwright-core";
import fs from "fs";
import path from "path";
import { ROUTES, DEV_URL, DENSE_DIR, resolveChrome, parseArgs } from "./routes.mjs";

const args = parseArgs();
const onlyRoute = args.route || null;

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const EXEC = await resolveChrome();
const browser = await chromium.launch({ executablePath: EXEC, headless: true });

const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
if (routes.length === 0) {
  console.error(`No ROUTES match --route=${onlyRoute}`);
  process.exit(2);
}

let totalErrors = 0;

for (const route of routes) {
  const OUT = DENSE_DIR(route.name);
  fs.rmSync(OUT, { recursive: true, force: true });
  fs.mkdirSync(OUT, { recursive: true });

  const url = `${DEV_URL}${route.path}${route.path.includes("?") ? "&" : "?"}skippreload`;
  const VH = 900;
  const page = await browser.newPage({ viewport: { width: 1440, height: VH } });
  const errors = [];
  page.on("console", (m) => m.type() === "error" && errors.push(m.text().slice(0, 300)));
  page.on("pageerror", (e) => errors.push("PAGEERROR: " + String(e).slice(0, 300)));

  await page.goto(url, { waitUntil: "load", timeout: 60000 });
  await sleep(4500);

  const H = await page.evaluate(() => document.documentElement.scrollHeight);
  const STEP = Math.round(VH * 0.55);
  console.log(`[${route.name}] scrollHeight=${H} step=${STEP}`);

  let i = 0;
  for (let y = 0; y < H - VH + STEP; y += STEP) {
    const target = Math.min(y, H - VH);
    await page.evaluate((t) => {
      if (window.__lenis) window.__lenis.scrollTo(t, { immediate: true });
      else window.scrollTo(0, t);
      if (window.__snapCam) window.__snapCam();
