1	/**
2	 * MagneticButton — cuberto-style magnet (heavier retune for the rebuild).
3	 *
4	 * The root is pulled toward the cursor and an inner label span trails at half
5	 * the strength, giving a weighty, layered parallax. Movement is deliberate and
6	 * non-elastic (EASE.SETTLE only) — never bouncy. The rect is read once per
7	 * pointerenter; the per-move path allocates nothing (two pre-built quickTo
8	 * setters mutate the same two transforms).
9	 *
10	 * Props:
11	 *   as        string  "button" (default) | "a" | any tag. as="a" + href works.
12	 *   strength  number  0.35    root pull factor; label trails at strength*0.5.
13	 *   className string  ""      passthrough to the rendered element.
14	 *   children  node            label content (wrapped in the trailing span).
15	 *   ...rest                   forwarded to the element (href, onClick, type…).
16	 *
17	 * Gate (scar #8 + coarse): useCoarsePointer() OR useMotionStatic() ⇒ render a
18	 * plain element (normal tap target) with data-static="true" — zero GSAP, no
19	 * listeners, full magnet skipped. The designed final state of a magnet at rest
20	 * IS the plain button, so this is also the correct static frame.
21	 *
22	 * Reduced/mobile fallback: same as the gate above (plain element).
23	 *
24	 * Scars: #1 n/a (no ScrollTrigger). All GSAP inside the component's own
25	 * gsap.context scoped to the root ref; cleanup reverts + removes listeners
26	 * (idempotent under StrictMode double-mount). quickTo built once, EASE.SNAP
27	 * never used (transforms here settle, they don't overshoot). One
28	 * getBoundingClientRect per enter is allowed (not per-frame).
29	 */
30	import { useLayoutEffect, useRef } from "react";
31	import { gsap } from "gsap";
32	import { useCoarsePointer, useMotionStatic } from "./useMotionStatic.js";
33	import { DUR, EASE } from "../../lib/motion.js";
34	
35	function MagneticButton({
36	  as = "button",
37	  strength = 0.35,
38	  className = "",
39	  children,
40	  ...rest
41	}) {
42	  const coarse = useCoarsePointer();
43	  const isStatic = useMotionStatic();
44	  const rootRef = useRef(null);
45	  const labelRef = useRef(null);
46	
47	  const plain = coarse || isStatic;
48	
49	  useLayoutEffect(() => {
50	    if (plain) return undefined;
51	    const root = rootRef.current;
52	    const label = labelRef.current;
53	    if (!root || !label) return undefined;
54	
55	    const ctx = gsap.context(() => {
56	      // Built once — zero per-move allocations. SETTLE = weighty, non-elastic.
57	      const xTo = gsap.quickTo(root, "x", { duration: 0.4, ease: EASE.SETTLE });
58	      const yTo = gsap.quickTo(root, "y", { duration: 0.4, ease: EASE.SETTLE });
59	      const lxTo = gsap.quickTo(label, "x", { duration: 0.4, ease: EASE.SETTLE });
60	      const lyTo = gsap.quickTo(label, "y", { duration: 0.4, ease: EASE.SETTLE });
61	
62	      // Cached per enter (one getBoundingClientRect per enter — not per frame).
63	      let cx = 0;
64	      let cy = 0;
65	
66	      const onEnter = () => {
67	        const r = root.getBoundingClientRect();
68	        cx = r.left + r.width / 2;
69	        cy = r.top + r.height / 2;
70	      };
71	      const onMove = (e) => {
72	        const dx = e.clientX - cx;
73	        const dy = e.clientY - cy;
74	        xTo(dx * strength);
75	        yTo(dy * strength);
76	        lxTo(dx * strength * 0.5);
77	        lyTo(dy * strength * 0.5);
78	      };
79	      const onLeave = () => {
80	        gsap.to(root, { x: 0, y: 0, duration: DUR.MD, ease: EASE.SETTLE });
81	        gsap.to(label, { x: 0, y: 0, duration: DUR.MD, ease: EASE.SETTLE });
82	      };
83	
84	      root.addEventListener("pointerenter", onEnter);
85	      root.addEventListener("pointermove", onMove);
86	      root.addEventListener("pointerleave", onLeave);
87	
88	      return () => {
89	        root.removeEventListener("pointerenter", onEnter);
90	        root.removeEventListener("pointermove", onMove);
91	        root.removeEventListener("pointerleave", onLeave);
92	      };
93	    }, rootRef);
94	
95	    return () => ctx.revert();
96	  }, [plain, strength]);
97	
98	  const Tag = as;
99	
100	  if (plain) {
101	    return (
102	      <Tag ref={rootRef} className={className} data-static="true" {...rest}>
103	        {children}
104	      </Tag>
105	    );
106	  }
107	
108	  return (
109	    <Tag
110	      ref={rootRef}
111	      data-magnetic-button
112	      className={`inline-block will-change-transform ${className}`}
113	      {...rest}
114	    >
115	      <span ref={labelRef} className="inline-block will-change-transform">
116	        {children}
117	      </span>
118	    </Tag>
119	  );
120	}
121	
122	export default MagneticButton;
123	export { MagneticButton };
124

