    const label = labelRef.current;
    if (!root || !label) return undefined;

    const ctx = gsap.context(() => {
      // Built once — zero per-move allocations. SETTLE = weighty, non-elastic.
      const xTo = gsap.quickTo(root, "x", { duration: 0.4, ease: EASE.SETTLE });
      const yTo = gsap.quickTo(root, "y", { duration: 0.4, ease: EASE.SETTLE });
      const lxTo = gsap.quickTo(label, "x", { duration: 0.4, ease: EASE.SETTLE });
      const lyTo = gsap.quickTo(label, "y", { duration: 0.4, ease: EASE.SETTLE });

      // Cached per enter (one getBoundingClientRect per enter — not per frame).
      let cx = 0;
      let cy = 0;

      const onEnter = () => {
        const r = root.getBoundingClientRect();
        cx = r.left + r.width / 2;
        cy = r.top + r.height / 2;
      };
      const onMove = (e) => {
        const dx = e.clientX - cx;
        const dy = e.clientY - cy;
        xTo(dx * strength);
        yTo(dy * strength);
        lxTo(dx * strength * 0.5);
        lyTo(dy * strength * 0.5);
      };
      const onLeave = () => {
        gsap.to(root, { x: 0, y: 0, duration: DUR.MD, ease: EASE.SETTLE });
        gsap.to(label, { x: 0, y: 0, duration: DUR.MD, ease: EASE.SETTLE });
      };

      root.addEventListener("pointerenter", onEnter);
      root.addEventListener("pointermove", onMove);
      root.addEventListener("pointerleave", onLeave);

      return () => {
        root.removeEventListener("pointerenter", onEnter);
        root.removeEventListener("pointermove", onMove);
        root.removeEventListener("pointerleave", onLeave);
      };
    }, rootRef);

    return () => ctx.revert();
  }, [plain, strength]);

  const Tag = as;

  if (plain) {
    return (
      <Tag ref={rootRef} className={className} data-static="true" {...rest}>
        {children}
      </Tag>
    );
  }

  return (
    <Tag
      ref={rootRef}
      data-magnetic-button
      className={`inline-block will-change-transform ${className}`}
      {...rest}
    >
      <span ref={labelRef} className="inline-block will-change-transform">
        {children}
      </span>
    </Tag>
  );
}

export default MagneticButton;
export { MagneticButton };

