/**
 * W2 — Industry-solutions skyline (Work) — the [data-showpiece="skyline"] act.
 *
 * ============================== S12 CONTRACT ===============================
 * - Mount: [data-showpiece="skyline"] (below), position:relative. S12 MAY
 *   attach the instanced GL extrude as an `absolute inset-0` child of this
 *   mount — ONE instanced draw (instanceMatrix/instanceColor, never 9 meshes,
 *   <= 40 draw calls), lazy chunk only, desktop full tier only.
 * - Data binding: the 9 cards bind src/data/industries.js (INDUSTRIES — 9 of
 *   {industry,stat,subtitle,before,result,after}). Each card root carries
 *   data-industry="<slug>" so GL instances map 1:1 to cards.
 * - THE DOM card-field below ([data-skyline-field]) IS the lite/none design:
 *   reduced-motion + mobile render it static with before/after both shown and
 *   final stat numbers (scar #8 — never a blank). S12 must KEEP it as the
 *   fallback and gate the canvas off it, not replace it.
 * - Any pin/scrub S12 adds registers via useRouteScrollContext().add()
 *   (scar #9) with a scar-#5 latch; ZERO `three` bytes on lite/none tiers.
 * ===========================================================================
 *
 * This sprint is pure DOM/GSAP (no three imports anywhere on Work). Travel
 * vectors: the 9 volumes RISE (InkReveal from="up", diagonal stagger) while
 * each 3-card row counter-PANS horizontally (ParallaxLayer axis="x",
 * alternating direction per row — the field drifts like a panned drafting
 * sheet). Stats + result figures CountStrike to their locked values; the
 * non-numeric stats render static. Locked facts (9 names + 9 stats + 9
 * results) come from src/data/industries.js, never hand-typed.
 */
import { INDUSTRIES } from "../../data/industries.js";
import {
  Section,
  SectionHeader,
  InkReveal,
  ParallaxLayer,
  CountStrike,
} from "../../components/motion/index.js";

function slugify(s) {
  return s
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "");
}

/**
 * Numeric-leading figures count-strike to their exact locked string
 * ("98% defect-free output" → to=98, suffix="% defect-free output");
 * non-numeric figures ("Real-time fraud detection") render static.
 * The DOM always ships the final verbatim string either way.
 */
function Figure({ value, className = "" }) {
  const m = /^(\d+(?:\.\d+)?)(.*)$/.exec(value);
  if (!m) return <span className={className}>{value}</span>;
  const decimals = (m[1].split(".")[1] || "").length;
  return (
    <CountStrike
      to={parseFloat(m[1])}
      decimals={decimals}
      suffix={m[2]}
      className={className}
    />
  );
}

// 3 rows × 3 volumes — the row is the pan unit, the card is the rise unit.
const ROWS = [INDUSTRIES.slice(0, 3), INDUSTRIES.slice(3, 6), INDUSTRIES.slice(6, 9)];

export default function SkylineField() {
  return (
    <Section id="industries" bordered className="overflow-x-clip">
      <SectionHeader
        eyebrow="Industry solutions"
        title="Nine verticals, drafted to spec."
        lead="Every agent ships with the before-state it replaces, a measured result, and the after-state it runs. The numbers are the design."
      />
      <div data-showpiece="skyline" className="relative mt-12">
        <div data-skyline-field="" className="flex flex-col gap-6">
          {ROWS.map((row, r) => (
            <ParallaxLayer
              key={r}
              axis="x"
              speed={r % 2 === 0 ? -0.09 : 0.09}
              className="will-change-transform"
            >
              <ul className="grid gap-6 md:grid-cols-3">
                {row.map((a, i) => (
                  <InkReveal
                    as="li"
                    key={a.industry}
                    from="up"
                    delay={i * 0.07 + r * 0.04}
                    data-industry={slugify(a.industry)}
                    className="flex flex-col rounded-md border border-line bg-surface p-7"
                  >
                    <p className="font-mono text-mono-label uppercase text-muted">
                      {a.industry}
                    </p>
                    <p className="mt-3 font-display text-title font-semibold leading-[1.15] text-accent">
                      <Figure value={a.stat} />
                    </p>
                    <p className="mt-2 font-body text-small text-ink-dim">
                      {a.subtitle}
                    </p>
                    <div className="mt-6 flex-1 border-t border-line pt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        before
                      </p>
                      <p className="mt-1.5 font-body text-small text-ink-dim">
                        {a.before}
                      </p>
                    </div>
                    <div className="mt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        result
                      </p>
                      <p className="mt-1.5 font-display text-[1.375rem] font-semibold leading-snug text-ink">
                        <Figure value={a.result} />
                      </p>
                    </div>
                    <div className="mt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        after
                      </p>
                      <p className="mt-1.5 font-body text-small text-ink-dim">
                        {a.after}
                      </p>
                    </div>
                  </InkReveal>
                ))}
              </ul>
