// the real horizontal case-study chapters + the extrude skyline.
export default function Work() {
  useDocumentHead(SEO["/work"]);
  // Route-scoped trigger context (scar #9) — S07 registers triggers via add().
  const { scopeRef } = useRouteScrollContext();

  return (
    <div ref={scopeRef}>
