            </article>
          ))}
        </div>
      </StubSection>

      {/* W2 ★ industry-solutions skyline showpiece mount (S11/S12 fills). */}
      <StubSection
        id="industries"
        eyebrow="Nine industries"
        title="A drafted field of agents"
        mount="skyline"
      >
        <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
