              </p>
              <p className="mt-2 font-body text-small text-ink-dim">
                <span className="text-muted">After:</span> {a.after}
              </p>
            </article>
          ))}
        </div>
      </StubSection>

      {/* W3 recap CTA. */}
      <StubSection id="recap" eyebrow="Next step" title="Want this for your business?">
        <div className="flex flex-wrap gap-4">
          <a
            href={LINKS.calendly}
            target="_blank"
            rel="noopener noreferrer"
            className="rounded-sm bg-accent px-5 py-3 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
          >
            Book a call
