          <Link
            to="/contact"
            className="rounded-sm border border-line-2 px-5 py-3 font-body text-sm font-medium text-ink transition-colors hover:border-accent"
          >
            Contact us
          </Link>
        </div>
      </StubSection>
    </div>
  );
}

