// verify.mjs — route-driven assertion suite (v0).
//
// Boots playwright-core against the running dev server (:5173) and asserts the
// invariants that must hold on every build. v0 targets the CURRENT single-page
// site; sprints extend ROUTES + add route-aware checks via the check() harness.
//
// Usage:
//   node scripts/qa/verify.mjs               full suite, all ROUTES
//   node scripts/qa/verify.mjs --route=/     restrict to one route
//   node scripts/qa/verify.mjs --skippreload pass ?skippreload to every load
//
// Exit 0 only if every check passes; non-zero with a failure list otherwise.
import fs from "fs";
import { chromium } from "playwright-core";
import { ROUTES, DEV_URL, resolveChrome, parseArgs } from "./routes.mjs";

// axe-core source, injected per page for the a11y/contrast audit (WCAG 2 A+AA).
const AXE_SOURCE = fs.readFileSync(
  new URL("../../node_modules/axe-core/axe.min.js", import.meta.url),
  "utf8"
);

const args = parseArgs();
const SKIP = args.skippreload ? "skippreload" : "";
const onlyRoute = args.route || null;

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

// ---- check() harness -------------------------------------------------------
const results = [];
function check(name, ok, info = "") {
  results.push({ name, ok: !!ok, info });
  console.log(`${ok ? "PASS" : "FAIL"} ${name}${info ? `  ${info}` : ""}`);
}

// Any of these fetched while reduced-motion / mobile / a no-GL route is active
// is a chunk-gating leak (scar #10 + perf budget). Matches Vite dep-optimized
// paths and any future manual GL chunk names.
const GL_CHUNKS =
  /node_modules\/\.vite\/deps\/(three|@react-three|postprocessing)|node_modules\/(three|@react-three|postprocessing)|\b(three|drei|HeroCanvas|GLStage|webgl|PipelineScene|[A-Za-z]*Scene)[-.][\w]+\.js/i;

// S07 — the /work locked facts (PROTOCOL §8; sprint-07 §5), asserted VERBATIM.
// Desktop asserts them post-scroll (CountStrike rewinds at mount and commits on
// strike); reduced/mobile assert them immediately (static tier ships finals).
const WORK_NAMES = [
  "Manufacturing", "Legal Services", "Customs Broking", "Financial Technology",
  "Enterprise Management Transformation", "Real Estate Marketing",
  "HR Tech - First Hires", "Codebase Migration Assistant", "VIP Assistance",
];
const WORK_STATS = [
  "98% QC accuracy", "10x throughput", "99.3% classification accuracy",
  "Real-time fraud detection", "60+ processes automated",
  "240% listing exposure increase", "90% screening automation",
  "Full migration documentation", "92% task automation rate",
];
const WORK_RESULTS = [
  "98% defect-free output", "87% cost reduction", "72% faster clearance",
  "94% reduction in manual reconciliation", "3.2x operational efficiency",
  "3.8x inbound lead uplift", "74% faster time-to-hire",
  "80% technical debt reduction", "5.5hrs/day reclaimed per exec",
];
const WORK_CASES = [
  "First-Contact Agentic Legal Document Generator",
  "Local Agentic AI-Based Data Analyst for SMEs",
  "4-6 hours", "under 10 minutes",
];

// Draw-call measurement: composer passes are only counted with autoReset off,
// accumulated across ~10 ticks then averaged (autoReset-on reports just the
// final screen-quad pass == 1). Returns -1 when no GL context (window.__gl).
async function measureDrawCalls(page) {
  return page.evaluate(
    () =>
      new Promise((res) => {
        const gl = window.__gl;
        if (!gl) return res(-1);
        gl.info.autoReset = false;
        gl.info.reset();
        if (window.__frame) window.__frame.needsFrames = 30;
        let ticks = 0;
        const tick = () => {
          if (++ticks < 10) return requestAnimationFrame(tick);
          const avg = Math.round(gl.info.render.calls / ticks);
          gl.info.autoReset = true;
          res(avg);
        };
        requestAnimationFrame(tick);
      })
  );
}

// ScrollTrigger count, or -1 when the page hasn't exposed window.__stCount yet
// (current site does not). Callers skip gracefully on -1.
function stCount(page) {
  return page.evaluate(() => (window.__stCount ? window.__stCount() : -1));
}

const EXEC = await resolveChrome();
const browser = await chromium.launch({ executablePath: EXEC, headless: true });

const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
// "/lab" is not a ROUTES entry (dev-only bench) — --route=/lab runs just the
// S04 lab suite below.
if (routes.length === 0 && onlyRoute !== "/lab") {
  console.error(`No ROUTES match --route=${onlyRoute}`);
  process.exit(2);
}

for (const route of routes) {
  const url = DEV_URL + route.path + (SKIP ? (route.path.includes("?") ? "&" : "?") + SKIP : "");

  // ---- DESKTOP pass: load clean, audit links/integrations, GL on showpiece --
  {
    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
    const consoleErrors = [];
    const pageErrors = [];
    const requests = [];
    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
    page.on("request", (r) => requests.push(r.url()));

    let emailjsReq = null;
    await page.route("**/api.emailjs.com/**", (r) => {
      const req = r.request();
      // Keep the FULL post body — service/template ids live deep inside the
      // multipart form-data, well past any fixed slice. Slice only for display.
      emailjsReq = { url: req.url(), method: req.method(), post: req.postData() || "" };
      r.fulfill({ status: 200, body: "OK" });
    });

    await page.goto(url, { waitUntil: "load", timeout: 60000 });
    await sleep(3500);

    const tag = `[${route.name}]`;

    // Route mounts its OWN stub (not the catch-all NotFound, not another page).
    // Asserted by the route's owned section ids being present AND the 404 marker
    // being absent. This is the per-route mount + deep-reload SPA-fallback proof:
    // we navigated directly to `url` (e.g. /work) and the real route mounted.
    const mount = await page.evaluate((ids) => ({
      ownedPresent: ids.filter((id) => !!document.getElementById(id)).length,
      ownedTotal: ids.length,
      isNotFound: !!document.getElementById("not-found"),
    }), route.ownedIds || []);
    check(
      `${tag} route mounts own stub (deep-reload SPA fallback)`,
      mount.ownedTotal > 0 && mount.ownedPresent === mount.ownedTotal && !mount.isNotFound,
      `(${mount.ownedPresent}/${mount.ownedTotal} owned ids, notFound=${mount.isNotFound})`
    );

    // Nav links present.
    const navCount = await page.evaluate(
      () => document.querySelectorAll("nav a, nav button").length
    );
    check(`${tag} nav links present`, navCount >= 5, `(${navCount})`);

    // Link / integration audit.
    const links = await page.evaluate(() => ({
      linkedinMembers: document.querySelectorAll('a[href*="linkedin.com/in/"]').length,
      linkedinCompany: document.querySelectorAll('a[href*="linkedin.com/company/"]').length,
      calendly: document.querySelectorAll('a[href*="calendly.com/sachmeet-kartar/30min"]').length,
      mailto: document.querySelectorAll('a[href="mailto:hello@kartar.ai"]').length,
      sender:
        !!document.querySelector('[data-sender-form-id]') ||
        !!document.querySelector('#sender-form'),
      fields: {
        from_name: !!document.querySelector('[name="from_name"]'),
        from_email: !!document.querySelector('[name="from_email"]'),
        from_phone: !!document.querySelector('[name="from_phone"]'),
        message: !!document.querySelector('[name="message"]'),
      },
    }));
    // Per-route INTEGRATION expectations (route.expect, from routes.mjs). The
    // single page is now split across 4 routes, so the contract is route-aware:
    // the 18 team LinkedIn links live only on the `team` route; the EmailJS form
    // only on the `contactForm` route; footer integrations + a Calendly CTA on
    // every route. facts_check.mjs still asserts the FULL contract site-wide.
    const exp = route.expect || {};
    if (exp.team) {
      check(`${tag} 18 LinkedIn member links`, links.linkedinMembers === 18, `(${links.linkedinMembers})`);
    }
    if (exp.companyLinked) {
      check(`${tag} >=1 company LinkedIn`, links.linkedinCompany >= 1, `(${links.linkedinCompany})`);
    }
    const calMin = exp.calendlyMin ?? 3;
    check(`${tag} >=${calMin} Calendly links`, links.calendly >= calMin, `(${links.calendly})`);
    if (exp.mailto) {
      check(`${tag} mailto hello@kartar.ai`, links.mailto >= 1);
    }
    if (exp.senderMount) {
      check(`${tag} Sender form mount present`, links.sender);
    }
    if (exp.contactForm) {
      check(
        `${tag} EmailJS fields present`,
        links.fields.from_name && links.fields.from_email && links.fields.from_phone && links.fields.message,
        `(name=${links.fields.from_name} email=${links.fields.from_email} phone=${links.fields.from_phone} msg=${links.fields.message})`
      );
    }

    // EmailJS stub-submit: fill + submit, assert the request is formed with the
    // right service/template ids and the success text appears. Never sent — the
    // api.emailjs.com route is intercepted and fulfilled with OK.
    const hasContact = await page.evaluate(() => !!document.querySelector('form [name="from_name"]'));
    if (hasContact) {
      await page.evaluate(() => {
        const el = document.querySelector('form [name="from_name"]')?.closest("section") || document.querySelector("#contact");
        if (!el) return;
        const top = el.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY);
        if (window.__lenis) window.__lenis.scrollTo(top, { immediate: true });
        else window.scrollTo(0, top);
      });
      await sleep(1000);
      await page.fill('[name="from_name"]', "Verification Bot");
      await page.fill('[name="from_email"]', "verify@example.com");
      await page.fill('[name="from_phone"]', "+91 00000 00000");
      await page.fill('[name="message"]', "Automated verification - not a real enquiry.");
      // force: the live Sender iframe (footer, cross-origin) jitters document
      // height a few px per frame, so Playwright's "stable" actionability wait
      // never settles. The click itself + the request/success assertions below
      // are unaffected (S06: observed 27/30 distinct rAF samples of docH).
      await page.click('form button[type="submit"]', { force: true });
      await sleep(2500);

      check(
        `${tag} EmailJS request formed (stubbed)`,
        !!emailjsReq,
        emailjsReq ? `→ ${emailjsReq.method} ${emailjsReq.url.slice(0, 50)}` : ""
      );
      const post = emailjsReq?.post || "";
      check(
        `${tag} EmailJS service_gtn59h8 in request`,
        post.includes("service_gtn59h8"),
        post ? "" : "(no post body captured)"
      );
      check(
        `${tag} EmailJS template_2l3bp6f in request`,
        post.includes("template_2l3bp6f"),
        post ? "" : "(no post body captured)"
      );
      const success = await page.evaluate(() =>
        document.body.innerText.includes("Message sent. We'll get back to you within 24 hours.")
      );
      check(`${tag} success message shown`, success);
    }

    // GL chunk-gating on desktop: a route with NO showpiece must never fetch GL
    // chunks. (A showpiece route legitimately may — checked only on reduced/mobile.)
    if (!route.showpiece) {
      const leaked = requests.filter((u) => GL_CHUNKS.test(u));
      check(`${tag} no GL chunks on no-showpiece route (desktop)`, leaked.length === 0, leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : "");
    } else {
      const calls = await measureDrawCalls(page);
      // -1 => no __gl yet; treat as informational pass (showpiece may predate
      // the GL-info hook). Once present, enforce the <=40 budget.
      check(
        `${tag} draw calls <= 40 (showpiece)`,
        calls === -1 || (calls > 0 && calls <= 40),
        `(${calls === -1 ? "no __gl hook yet" : calls})`
      );
    }

    // __stCount nav-leak baseline — only meaningful once exposed; skip otherwise.
    const st = await stCount(page);
    if (st >= 0) check(`${tag} ScrollTrigger count > 0`, st > 0, `(${st})`);

    // S03 backbone globals: Lenis instance + trigger counter (desktop is the
    // non-reduced, non-mobile tier, so Lenis MUST exist here).
    const backbone = await page.evaluate(() => ({
      lenis: !!(window.__lenis && typeof window.__lenis.scrollTo === "function"),
      stCountFn: typeof window.__stCount === "function",
      preloaderDone: window.__preloaderDone === true,
    }));
    check(`${tag} window.__lenis exposed (has scrollTo)`, backbone.lenis);
    check(`${tag} window.__stCount is a function`, backbone.stCountFn);
    check(`${tag} preloaderDone fired`, backbone.preloaderDone);

    // ---- S05 chrome suite: navbar/footer/cursor/seam/newsletter ------------
    const chrome = await page.evaluate(() => {
      const hrefs = ["/", "/work", "/studio", "/contact"];
      const seam = document.querySelector("[data-route-seam]");
      const seamStyle = seam ? getComputedStyle(seam) : null;
      return {
        headerLinks: hrefs.filter((h) => !!document.querySelector(`header nav a[href="${h}"]`)).length,
        footerLinks: hrefs.filter((h) => !!document.querySelector(`footer a[href="${h}"]`)).length,
        cursor: !!document.querySelector("[data-magnetic-cursor]"),
        senderContainers: document.querySelectorAll("[data-sender-form-id]").length,
        companyLinks: document.querySelectorAll('a[href*="linkedin.com/company/"]').length,
        newsletterInFooter: !!document.querySelector("footer #newsletter"),
        seam: !!seam,
        seamTransform: seamStyle ? seamStyle.transform : "missing",
        seamOverflowY: seamStyle ? seamStyle.overflowY : "missing",
      };
    });
    check(`${tag} navbar renders all 4 NAV route links`, chrome.headerLinks === 4, `(${chrome.headerLinks}/4)`);
    check(`${tag} footer renders all 4 NAV route links (one NAV source)`, chrome.footerLinks === 4, `(${chrome.footerLinks}/4)`);
    check(`${tag} custom cursor active (desktop fine pointer)`, chrome.cursor);
    check(`${tag} exactly ONE Sender container (StrictMode-safe)`, chrome.senderContainers === 1, `(${chrome.senderContainers})`);
    check(`${tag} exactly ONE company LinkedIn link`, chrome.companyLinks === 1, `(${chrome.companyLinks})`);
    check(`${tag} #newsletter lives in the footer`, chrome.newsletterInFooter);
    check(
      `${tag} seam is not a scroll container (scar #2)`,
      chrome.seam && chrome.seamTransform === "none" && chrome.seamOverflowY === "visible",
      `(transform=${chrome.seamTransform} overflowY=${chrome.seamOverflowY})`
    );

    // Real window still scrolls THROUGH the seam (no nested scroller).
    const winScrollY = await page.evaluate(async () => {
      if (window.__lenis) window.__lenis.scrollTo(600, { immediate: true });
      else window.scrollTo(0, 600);
      await new Promise((r) => setTimeout(r, 400));
      return window.scrollY;
    });
    check(`${tag} real window scrolls through the seam (scar #2)`, winScrollY > 300, `(scrollY=${winScrollY})`);

    // Locked CTA→newsletter behavior via the shared helper (dev-only global).
    const reach = await page.evaluate(async () => {
      if (typeof window.__goToNewsletter !== "function") return { ok: false, why: "helper global missing" };
      const issued = window.__goToNewsletter();
      await new Promise((r) => setTimeout(r, 1800));
      const el = document.getElementById("newsletter");
      if (!el) return { ok: false, why: "no #newsletter" };
      const rect = el.getBoundingClientRect();
      return {
        ok: issued && rect.top < window.innerHeight && rect.bottom > 0,
        why: `top=${Math.round(rect.top)}`,
      };
    });
    check(`${tag} goToNewsletter lands viewport on #newsletter`, reach.ok, `(${reach.why})`);

    // ---- S06 home suite: composed Home, showpiece mounts, facts, CTA -------
    if (route.path === "/") {
      const home = await page.evaluate(() => {
        const text = document.body.textContent;
        const probe = (sel) => {
          const el = document.querySelector(sel);
          if (!el) return null;
          return {
            rel: getComputedStyle(el).position === "relative",
            w: el.offsetWidth,
            h: el.offsetHeight,
          };
        };
        const has = (arr) => arr.filter((s) => text.includes(s)).length;
        const poster = document.querySelector('[data-showpiece="hero"] [data-hero-poster]');
        return {
          hero: probe('[data-showpiece="hero"]'),
          heroPoster: !!poster && poster.childElementCount > 0,
          pipe: probe('[data-showpiece="pipeline"]'),
          pipeFallback: !!document.querySelector('[data-showpiece="pipeline"] [data-pipeline-fallback]'),
          stages: has(["Read", "Ground", "Reason", "Classify", "Cite"]),
          numbers: has(["8471.30", "₹2,41,800", "BCD 0%", "IGST 18%", "duty payable ₹0"]),
          industries: has(["Logistics", "Legal Tech", "Healthcare", "Finance", "Agriculture", "E-commerce", "Manufacturing", "Education"]),
          services: has(["Agentic AI Workflows", "Vertical SaaS Products", "AI Strategy & Scoping"]),
          testimonials: has(["CTO, Fintech Startup", "Operations Head, Logistics Co.", "Founder, Legal Tech Startup"]),
          heroHeadline:
            text.includes("Some industries haven't changed in 30 years.") &&
            text.includes("We're changing them now."),
          trustBar: has(["Pilot to production in weeks", "Services + Products", "Indian-first, not localised", "Timeline", "What we build", "Approach"]),
          heroCalendly: !!document.querySelector('#hero a[href*="calendly.com/sachmeet-kartar/30min"]'),
          heroToWork: !!document.querySelector('#hero a[href="/work"]'),
          ctaNewsletterBtn: !!document.querySelector('#cta a[href="#newsletter"]'),
          ctaCalendly: !!document.querySelector('#cta a[href*="calendly.com"]'),
        };
      });
      check(
        `${tag} hero mount relative + sized + non-blank poster (S10 contract)`,
        !!home.hero && home.hero.rel && home.hero.w > 200 && home.hero.h > 200 && home.heroPoster,
        `(${home.hero ? `rel=${home.hero.rel} ${home.hero.w}x${home.hero.h}` : "missing"} poster=${home.heroPoster})`
      );
      check(
        `${tag} pipeline mount relative + static fallback child (S11 contract)`,
        !!home.pipe && home.pipe.rel && home.pipeFallback,
        `(${home.pipe ? `rel=${home.pipe.rel}` : "missing"} fallback=${home.pipeFallback})`
      );
      check(`${tag} 5 pipeline stage labels present`, home.stages === 5, `(${home.stages}/5)`);
      check(`${tag} pipeline key numbers in static fallback`, home.numbers === 5, `(${home.numbers}/5)`);
      check(`${tag} 8 industry names present`, home.industries === 8, `(${home.industries}/8)`);
      check(`${tag} 3 service titles present`, home.services === 3, `(${home.services}/3)`);
      check(`${tag} 3 testimonial attributions present`, home.testimonials === 3, `(${home.testimonials}/3)`);
      check(
        `${tag} hero headline + trust bar pairs present`,
        home.heroHeadline && home.trustBar === 6,
        `(headline=${home.heroHeadline} trust=${home.trustBar}/6)`
      );
      check(
        `${tag} hero CTAs: Calendly primary + /work secondary`,
        home.heroCalendly && home.heroToWork,
        `(calendly=${home.heroCalendly} work=${home.heroToWork})`
      );
      check(
        `${tag} CTA banner buttons (newsletter + Calendly)`,
        home.ctaNewsletterBtn && home.ctaCalendly,
        `(newsletter=${home.ctaNewsletterBtn} calendly=${home.ctaCalendly})`
      );

      // Locked behavior: the CTA banner's own button reaches #newsletter.
      const ctaReach = await page.evaluate(async () => {
        const btn = document.querySelector('#cta a[href="#newsletter"]');
        if (!btn) return { ok: false, why: "no CTA button" };
        const top = btn.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY) - 240;
        if (window.__lenis) window.__lenis.scrollTo(top, { immediate: true });
        else window.scrollTo(0, top);
        await new Promise((r) => setTimeout(r, 700));
        btn.click();
        await new Promise((r) => setTimeout(r, 1800));
        const el = document.getElementById("newsletter");
        if (!el) return { ok: false, why: "no #newsletter" };
        const rect = el.getBoundingClientRect();
        return { ok: rect.top < window.innerHeight && rect.bottom > 0, why: `top=${Math.round(rect.top)}` };
      });
      check(`${tag} CTA banner click lands viewport on #newsletter`, ctaReach.ok, `(${ctaReach.why})`);
    }

    // ---- S07 work suite: skyline mount, pinned-rail travel, facts, CTA -----
    if (route.path === "/work") {
      // (1) Static contracts at load.
      const work = await page.evaluate(() => {
        const mountEl = document.querySelector('[data-showpiece="skyline"]');
        const cards = [...document.querySelectorAll('[data-showpiece="skyline"] [data-industry]')];
        return {
          mount: !!mountEl,
          mountRel: mountEl ? getComputedStyle(mountEl).position === "relative" : false,
          field: !!document.querySelector('[data-showpiece="skyline"] [data-skyline-field]'),
          cards: cards.length,
          cardsNonBlank: cards.length > 0 && cards.every((c) => c.textContent.trim().length > 80),
          pipelineMount: !!document.querySelector('[data-showpiece="pipeline"]'),
          rail: !!document.getElementById("case-rail"),
          pins: document.querySelectorAll(".pin-spacer").length,
        };
      });
      check(
        `${tag} skyline mount relative + DOM field child (S12 contract)`,
        work.mount && work.mountRel && work.field,
        `(mount=${work.mount} rel=${work.mountRel} field=${work.field})`
      );
      check(
        `${tag} skyline holds 9 non-blank industry cards`,
        work.cards === 9 && work.cardsNonBlank,
        `(${work.cards} cards, nonBlank=${work.cardsNonBlank})`
      );
      check(`${tag} NO pipeline mount on Work (IA reconciliation)`, !work.pipelineMount);
      check(`${tag} W1 case rail pinned (desktop)`, work.rail && work.pins >= 1, `(rail=${work.rail} pin-spacers=${work.pins})`);

      // (2) Horizontal travel: step into the pin, sample the track transform.
      const travel = await page.evaluate(async () => {
        const root = document.getElementById("case-rail");
        if (!root) return { ok: false, why: "no #case-rail" };
        const track = root.querySelector(":scope > div:last-child");
        const spacer = root.closest(".pin-spacer") || root;
        const topAbs = spacer.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY);
        const go = (y) => (window.__lenis ? window.__lenis.scrollTo(y, { immediate: true }) : window.scrollTo(0, y));
        go(topAbs + 10);
        await new Promise((r) => setTimeout(r, 800));
        const t0 = getComputedStyle(track).transform;
        go(topAbs + window.innerHeight * 0.6);
        await new Promise((r) => setTimeout(r, 1000));
        const t1 = getComputedStyle(track).transform;
        return { ok: t0 !== t1, why: `${t0.slice(0, 32)} -> ${t1.slice(0, 32)}` };
      });
      check(`${tag} W1 rail travels horizontally under scroll`, travel.ok, `(${travel.why})`);

      // (3) Fling latch (scar #5): hard top, then one immediate jump far past
      // the rail end — the latch must commit the end state.
      const latch = await page.evaluate(async () => {
        const root = document.getElementById("case-rail");
        if (!root) return "(no rail)";
        const spacer = root.closest(".pin-spacer") || root;
        const go = (y) => (window.__lenis ? window.__lenis.scrollTo(y, { immediate: true }) : window.scrollTo(0, y));
        go(0);
        await new Promise((r) => setTimeout(r, 600));
        const topAbs = spacer.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY);
        go(topAbs + window.innerHeight * 3);
        await new Promise((r) => setTimeout(r, 1400));
        return root.getAttribute("data-latched") || "(none)";
      });
      check(`${tag} W1 fling commits end state (scar #5 latch)`, latch === "end", `(data-latched=${latch})`);

      // (4) Walk the full page so every CountStrike fires, then assert the
      // locked facts verbatim — the strikes must COMMIT their final strings.
      await page.evaluate(async () => {
        const max = document.documentElement.scrollHeight - window.innerHeight;
        const go = (y) => (window.__lenis ? window.__lenis.scrollTo(y, { immediate: true }) : window.scrollTo(0, y));
        for (let f = 0; f <= 1.001; f += 0.1) {
          go(Math.round(max * Math.min(f, 1)));
          await new Promise((r) => setTimeout(r, 380));
        }
        await new Promise((r) => setTimeout(r, 1600));
      });
      const missing = await page.evaluate(
        (all) => all.filter((s) => !document.body.textContent.includes(s)),
        [...WORK_STATS, ...WORK_RESULTS, ...WORK_NAMES, ...WORK_CASES]
      );
      check(
        `${tag} 9 stats + 9 results + 9 names + 2 case concepts verbatim (post-strike)`,
        missing.length === 0,
        missing.length ? `missing: ${missing.join(" | ").slice(0, 160)}` : "(24 strings)"
      );
      const struck = await page.evaluate(() => ({
        struck: document.querySelectorAll('[data-count-strike][data-struck="true"]').length,
        total: document.querySelectorAll("[data-count-strike]").length,
      }));
      check(
        `${tag} CountStrikes committed (data-struck on all)`,
        struck.total >= 10 && struck.struck === struck.total,
        `(${struck.struck}/${struck.total})`
      );

      // (5) W3 CTA navigates to /contact (real router link), then back so the
      // remaining desktop checks (console/axe) still audit /work.
      await page.evaluate(async () => {
        const el = document.getElementById("recap");
        if (!el) return;
        const top = el.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY) - 80;
        if (window.__lenis) window.__lenis.scrollTo(top, { immediate: true });
        else window.scrollTo(0, top);
        await new Promise((r) => setTimeout(r, 700));
      });
      await page.click('#recap a[href="/contact"]', { force: true });
      await sleep(1100);
      const nav = await page.evaluate(() => ({
        path: window.location.pathname,
        mounted: !!document.getElementById("contact"),
      }));
      check(`${tag} W3 CTA routes to /contact`, nav.path === "/contact" && nav.mounted, `(path=${nav.path} mounted=${nav.mounted})`);
      await page.goBack();
      await sleep(1100);
      const backPath = await page.evaluate(() => window.location.pathname);
      check(`${tag} back on /work after CTA round-trip`, backPath === "/work", `(${backPath})`);
    }

    check(`${tag} zero console errors`, consoleErrors.length === 0, consoleErrors[0] || "");
    check(`${tag} zero page errors`, pageErrors.length === 0, pageErrors[0] || "");

    // ---- AXE a11y + contrast audit (WCAG 2 A+AA) ---------------------------
    // Readability/contrast is part of the gate, not a vibe: serious+critical
    // violations (color-contrast is "serious") fail rebuilt routes. The legacy
    // pre-rebuild route only logs, so the chain can't deadlock on old UI debt.
    try {
      await page.addScriptTag({ content: AXE_SOURCE });
      const axe = await page.evaluate(async () => {
        const res = await window.axe.run(document, {
          runOnly: { type: "tag", values: ["wcag2a", "wcag2aa"] },
          resultTypes: ["violations"],
        });
        return res.violations.map((v) => ({
          id: v.id, impact: v.impact, nodes: v.nodes.length, help: v.help,
        }));
      });
      const blocking = axe.filter((v) => v.impact === "critical" || v.impact === "serious");
      if (route.legacy) {
        check(
          `${tag} axe audit (legacy: informational)`,
          true,
          `(${blocking.length} serious+critical${blocking.length ? `: ${blocking.map((v) => v.id).join(", ").slice(0, 90)}` : ""})`
        );
      } else {
        check(
          `${tag} axe: no serious/critical violations`,
          blocking.length === 0,
          blocking[0] ? `${blocking[0].id} x${blocking[0].nodes} — ${blocking[0].help}`.slice(0, 120) : ""
        );
        const contrast = axe.find((v) => v.id === "color-contrast");
        check(`${tag} axe: text contrast (WCAG AA)`, !contrast, contrast ? `x${contrast.nodes} nodes failing` : "");
      }
    } catch (e) {
      check(`${tag} axe audit ran`, false, String(e).slice(0, 120));
    }

    await page.close();
  }

  // ---- REDUCED-MOTION pass: zero GL bytes, content still present ------------
  {
    const page = await browser.newPage({
      viewport: { width: 1440, height: 900 },
      reducedMotion: "reduce",
    });
    const requests = [];
    page.on("request", (r) => requests.push(r.url()));
    await page.goto(url, { waitUntil: "load", timeout: 60000 });
    await sleep(3000);
    await page.evaluate(() =>
      window.__lenis
        ? window.__lenis.scrollTo(document.body.scrollHeight, { immediate: true })
        : window.scrollTo(0, document.body.scrollHeight)
    );
    await sleep(2000);
    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
    check(
      `[${route.name}] reduced-motion: zero GL chunks fetched`,
      leaked.length === 0,
      leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : ""
    );
    if (route.mobileStatic) {
      const hasText = await page.evaluate(() => document.body.innerText.trim().length > 200);
      check(`[${route.name}] reduced-motion: content rendered (not blank)`, hasText);
    }
    // S03: reduced tier = native scroll (no Lenis), page fully scrollable — the
    // scrollTo-bottom above must have actually moved the window.
    const rm = await page.evaluate(() => ({
      scrolledY: window.scrollY,
      noLenis: typeof window.__lenis === "undefined",
    }));
    check(
      `[${route.name}] reduced-motion: native scroll reaches bottom`,
      rm.noLenis && rm.scrolledY > 100,
      `(lenis=${!rm.noLenis} scrollY=${rm.scrolledY})`
    );
    // S05: cursor gated OFF under prefers-reduced-motion (native cursor only).
    const rmCursor = await page.evaluate(() => !!document.querySelector("[data-magnetic-cursor]"));
    check(`[${route.name}] reduced-motion: no custom cursor`, !rmCursor);
    // S06: Home reduced tier = designed static finals (scar #8).
    if (route.path === "/") {
      const rm6 = await page.evaluate(() => ({
        pins: document.querySelectorAll(".pin-spacer").length,
        statics: document.querySelectorAll('#industries [data-static="true"], #services [data-static="true"], #testimonials [data-static="true"]').length,
        stages: ["Read", "Ground", "Reason", "Classify", "Cite"].every((s) => document.body.textContent.includes(s)),
        poster: !!document.querySelector('[data-showpiece="hero"] [data-hero-poster]'),
      }));
      check(`[${route.name}] reduced: zero pins on Home (scar #8)`, rm6.pins === 0, `(${rm6.pins})`);
      check(`[${route.name}] reduced: marquee/stack/rail render static tiers`, rm6.statics >= 3, `(${rm6.statics})`);
      check(`[${route.name}] reduced: pipeline static graph readable (5 stages)`, rm6.stages);
      check(`[${route.name}] reduced: hero poster rendered`, rm6.poster);
    }
    await page.close();
  }

  // ---- MOBILE pass: zero GL bytes, no horizontal overflow, content present --
  {
    const page = await browser.newPage({ viewport: { width: 390, height: 844 }, hasTouch: true });
    const requests = [];
    page.on("request", (r) => requests.push(r.url()));
    await page.goto(url, { waitUntil: "load", timeout: 60000 });
    await sleep(3000);
    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
    check(
      `[${route.name}] mobile: zero GL chunks fetched`,
      leaked.length === 0,
      leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : ""
    );
    const m = await page.evaluate(() => ({
      overflowX: document.documentElement.scrollWidth <= window.innerWidth + 1,
      hasText: document.body.innerText.trim().length > 200,
    }));
    check(`[${route.name}] mobile: no horizontal overflow`, m.overflowX);
    if (route.mobileStatic) check(`[${route.name}] mobile: content present`, m.hasText);

    // S05: cursor gated OFF on mobile; hamburger menu opens with all links.
    const mobChrome = await page.evaluate(() => ({
      cursor: !!document.querySelector("[data-magnetic-cursor]"),
      toggle: !!document.querySelector("[data-nav-toggle]"),
    }));
    check(`[${route.name}] mobile: no custom cursor`, !mobChrome.cursor);
    check(`[${route.name}] mobile: nav toggle present`, mobChrome.toggle);
    if (mobChrome.toggle) {
      await page.click("[data-nav-toggle]");
      await sleep(350);
      const menu = await page.evaluate(() => {
        const links = [...document.querySelectorAll("#mobile-menu a")];
        return {
          count: links.length,
          visible: links.length > 0 && links.every((a) => a.getBoundingClientRect().height > 0),
        };
      });
      check(
        `[${route.name}] mobile: menu opens (4 routes + Calendly tappable)`,
        menu.count >= 5 && menu.visible,
        `(${menu.count} links, visible=${menu.visible})`
      );
    }
    // S06: Home mobile tier = static finals, no pins, poster + pipeline graph.
    if (route.path === "/") {
      const mob6 = await page.evaluate(() => ({
        pins: document.querySelectorAll(".pin-spacer").length,
        stages: ["Read", "Ground", "Reason", "Classify", "Cite"].every((s) => document.body.textContent.includes(s)),
        poster: !!document.querySelector('[data-showpiece="hero"] [data-hero-poster]'),
      }));
      check(
        `[${route.name}] mobile: zero pins + pipeline static + hero poster`,
        mob6.pins === 0 && mob6.stages && mob6.poster,
        `(pins=${mob6.pins} stages=${mob6.stages} poster=${mob6.poster})`
      );
    }
    await page.close();
  }
}

// ---- S03 backbone suite: preloader lifecycle + trigger-leak cycle ----------
// Runs once (home-anchored); skipped when --route targets another path.
if (!onlyRoute || onlyRoute === "/") {
  // (a) Preloader first-load lifecycle: veil appears, finishes, unlocks.
  {
    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
    const consoleErrors = [];
    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 200)));
    await page.goto(DEV_URL + "/", { waitUntil: "load", timeout: 60000 });

    let sawVeil = true;
    try {
      await page.waitForSelector("[data-preloader]", { timeout: 5000 });
    } catch {
      sawVeil = false;
    }
    check("[backbone] preloader veil shows on first load", sawVeil);

    let veilGone = true;
    try {
      await page.waitForSelector("[data-preloader]", { state: "detached", timeout: 10000 });
    } catch {
      veilGone = false;
    }
    check("[backbone] preloader completes and unmounts", veilGone);

    const post = await page.evaluate(() => ({
      done: window.__preloaderDone === true,
      unlocked: document.documentElement.style.overflow !== "hidden",
      scrollable: document.documentElement.scrollHeight > window.innerHeight,
    }));
    check("[backbone] preloaderDone fired after veil", post.done);
    check("[backbone] scroll unlocked after preloader", post.unlocked && post.scrollable,
      `(overflowUnlocked=${post.unlocked} scrollable=${post.scrollable})`);

    // (b) Once per session: an in-app nav must NOT re-show it…
    await page.click('nav a[href="/work"]');
    await sleep(800);
    const reshownNav = await page.evaluate(() => !!document.querySelector("[data-preloader]"));
    check("[backbone] preloader NOT re-shown on in-app nav", !reshownNav);
    // …and neither must a same-session reload (sessionStorage gate).
    await page.reload({ waitUntil: "load" });
    await sleep(1200);
    const reshownReload = await page.evaluate(() => ({
      veil: !!document.querySelector("[data-preloader]"),
      done: window.__preloaderDone === true,
    }));
    check("[backbone] preloader NOT re-shown on same-session reload", !reshownReload.veil);
    check("[backbone] preloaderDone still fires when session-skipped", reshownReload.done);
    check("[backbone] preloader suite: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
    await page.close();
  }

  // (c) ?skippreload bypass: no veil ever, preloaderDone still fires.
  {
    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
    await sleep(1000);
    const r = await page.evaluate(() => ({
      veil: !!document.querySelector("[data-preloader]"),
      done: window.__preloaderDone === true,
    }));
    check("[backbone] ?skippreload: no preloader node", !r.veil);
    check("[backbone] ?skippreload: preloaderDone still fired", r.done);
    await page.close();
  }

  // (d) THE leak assertion (scar #9): 3 full /->work->studio->contact->/ SPA
  // cycles; __stCount() must return to the post-load baseline after each.
  {
    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
    const pageErrors = [];
    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 200)));
    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
    // Steady state: Home's in-view once-strikes (InkReveal/SplitLines) self-kill
    // on completion (~2s incl. delays) — measure AFTER, so the baseline and the
    // post-cycle counts sample the same lifecycle moment (S06).
    await sleep(2600);

    const baseline = await stCount(page);
    check("[backbone] __stCount baseline > 0 (route sentinel alive)", baseline > 0, `(${baseline})`);

    const CYCLE = ["/work", "/studio", "/contact", "/"];
    const counts = [];
    for (let cycle = 1; cycle <= 3; cycle++) {
      for (const path of CYCLE) {
        await page.click(`nav a[href="${path}"]`);
        await sleep(450);
      }
      await sleep(2300); // debounced refresh + once-strike self-kills settle
      counts.push(await stCount(page));
    }
    // S06 note: Home now carries once:true strike triggers that self-kill on a
    // lifecycle (not page-load) clock, so the count is steady-state-dependent.
    // The leak invariant: identical counts across identically-timed cycles (a
    // leak compounds per cycle) AND zero orphaned triggers (a leaked trigger
    // points at a detached element). Baseline equality was the stub-era check.
    check(
      "[backbone] zero trigger leak across 3 route cycles",
      counts[0] > 0 && counts.every((c) => c === counts[0]) && Math.abs(counts[0] - baseline) <= 3,
      `(baseline=${baseline} after cycles=${counts.join(",")})`
    );
    const orphans = await page.evaluate(() => (window.__stOrphans ? window.__stOrphans() : -1));
    check("[backbone] zero orphaned triggers after cycles (scar #9)", orphans === 0, `(${orphans})`);
    check("[backbone] leak suite: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
    await page.close();
  }

  // (e) S05 chrome: nav links actually NAVIGATE (route changes + the new page
  // mounts through the transition seam), from both the navbar and the footer.
  {
    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
    const pageErrors = [];
    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 200)));
    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
    await sleep(1200);

    await page.click('header nav a[href="/work"]');
    await sleep(900);
    const toWork = await page.evaluate(() => ({
      path: window.location.pathname,
      mounted: !!document.getElementById("case-studies"),
    }));
    check(
      "[chrome] navbar link navigates / -> /work (page mounts in seam)",
      toWork.path === "/work" && toWork.mounted,
      `(path=${toWork.path} mounted=${toWork.mounted})`
    );

    await page.click('footer a[href="/studio"]');
    await sleep(900);
    const toStudio = await page.evaluate(() => ({
      path: window.location.pathname,
      mounted: !!document.getElementById("team"),
    }));
    check(
      "[chrome] footer link navigates /work -> /studio",
      toStudio.path === "/studio" && toStudio.mounted,
      `(path=${toStudio.path} mounted=${toStudio.mounted})`
    );

    // Condense-on-scroll: shell-level trigger flips data-condensed and SURVIVES
    // navigation (it lives outside the per-route context — the scar-#9 trap).
    const condense = await page.evaluate(async () => {
      const header = document.querySelector("header[class*='sticky']") || document.querySelector("header");
      if (window.__lenis) window.__lenis.scrollTo(400, { immediate: true });
      else window.scrollTo(0, 400);
      await new Promise((r) => setTimeout(r, 500));
      const condensed = header?.hasAttribute("data-condensed");
      if (window.__lenis) window.__lenis.scrollTo(0, { immediate: true });
      else window.scrollTo(0, 0);
      await new Promise((r) => setTimeout(r, 500));
      const expanded = !header?.hasAttribute("data-condensed");
      return { condensed, expanded };
    });
    check(
      "[chrome] navbar condenses on scroll + survives navigation",
      condense.condensed && condense.expanded,
      `(condensed=${condense.condensed} re-expanded=${condense.expanded})`
    );
    check("[chrome] nav suite: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
    await page.close();
  }
}

// ---- S04 lab suite: motion primitive proof bench (/lab, DEV-only) ----------
// /lab mounts every v2 primitive once (src/pages/Lab.jsx). Asserted per tier:
// desktop = motion tier (strikes fire, pins exist, latches commit), reduced +
// mobile = designed static finals (scar #8). The route only exists on the dev
// server — the prod build DCEs it out (checked separately via the build grep).
const LAB_BLOCKS = [
  "split-lines", "ink-reveal", "draft-line", "dimension-mark", "snap-stack",
  "axis-rail", "kinetic-marquee", "magnetic-button", "magnetic-cursor",
  "count-strike", "scrub-scene", "parallax-layer", "chapter-marker", "section",
];
const labWalk = async (page, steps = 12, settle = 650) => {
  for (let i = 1; i <= steps; i++) {
    await page.evaluate((f) => {
      const max = document.documentElement.scrollHeight - window.innerHeight;
      const y = Math.round(max * f);
      if (window.__lenis) window.__lenis.scrollTo(y, { immediate: true });
      else window.scrollTo(0, y);
    }, i / steps);
    await sleep(settle);
  }
};
