// ---- static tier: paint the final state once, register zero GSAP. --------
useLayoutEffect(() => {
  if (!isStatic) return undefined;
  const root = rootRef.current;
  if (root) root.setAttribute("data-state", "final");
  onProgressRef.current?.(1);
  return undefined;
}, [isStatic]);

// ---- motion tier: pin + scrub in this component's own context. -----------
useLayoutEffect(() => {
  if (isStatic) return undefined;
  const root = rootRef.current;
  if (!root) return undefined;

  const ctx = gsap.context(() => {
    // A single reusable progress proxy for the latch tweens — created ONCE,
    // overwritten on each latch so no per-fling allocation churn.
    const proxy = { p: 0 };
    let latchTween = null;

    // Hoisted style-writer for the optional --p custom property: no closure
    // allocation inside onUpdate.
    const rootEl = root;

    const emit = (p) => {
      onProgressRef.current?.(p);
      if (cssVar) rootEl.style.setProperty("--p", p);
    };

    const runLatch = (to) => {
      if (!latch) return;
      proxy.p = st.progress;
      if (latchTween) latchTween.kill();
      latchTween = gsap.to(proxy, {
        p: to,
        duration: DUR.XS,
        ease: EASE.SETTLE,
        overwrite: true,
        onUpdate: () => emit(proxy.p),
      });
    };

    const st = ScrollTrigger.create({
      trigger: root,
      start: "top top",
      end: length,
      pin: pin ? root : false,
      anticipatePin: 1,
      scrub,
      invalidateOnRefresh: true,
      onUpdate: (self) => emit(self.progress),
      // Scar #5 — fast fling past either edge commits the boundary state so
      // the scene is never stranded half-scrubbed.
      onLeave: () => runLatch(1),
      onLeaveBack: () => runLatch(0),
    });

    // Initial paint (scar #12 — start state committed inside the same
    // context that owns the trigger; if already past start on load this runs
    // with the correct progress on the next refresh anyway).
    emit(st.progress);
    rootEl.setAttribute("data-state", "live");
  }, root);

  return () => ctx.revert();
}, [isStatic, length, pin, scrub, latch, cssVar]);

return (

