// 3 rows × 3 volumes — the row is the pan unit, the card is the rise unit.
const ROWS = [INDUSTRIES.slice(0, 3), INDUSTRIES.slice(3, 6), INDUSTRIES.slice(6, 9)];

export default function SkylineField() {
  return (
    <Section id="industries" bordered className="overflow-x-clip">
      <SectionHeader
        eyebrow="Industry solutions"
        title="Nine verticals, drafted to spec."
        lead="Every agent ships with the before-state it replaces, a measured result, and the after-state it runs. The numbers are the design."
      />
      <div data-showpiece="skyline" className="relative mt-12">
        <div data-skyline-field="" className="flex flex-col gap-6">
          {ROWS.map((row, r) => (
            <ParallaxLayer
              key={r}
              axis="x"
              speed={r % 2 === 0 ? -0.09 : 0.09}
              className="will-change-transform"
            >
              <ul className="grid gap-6 md:grid-cols-3">
                {row.map((a, i) => (
                  <InkReveal
                    as="li"
                    key={a.industry}
                    from="up"
                    delay={i * 0.07 + r * 0.04}
                    data-industry={slugify(a.industry)}
                    className="flex flex-col rounded-md border border-line bg-surface p-7"
                  >
                    <p className="font-mono text-mono-label uppercase text-muted">
                      {a.industry}
                    </p>
                    <p className="mt-3 font-display text-title font-semibold leading-[1.15] text-accent">
                      <Figure value={a.stat} />
                    </p>
                    <p className="mt-2 font-body text-small text-ink-dim">
                      {a.subtitle}
                    </p>
                    <div className="mt-6 flex-1 border-t border-line pt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        before
                      </p>
                      <p className="mt-1.5 font-body text-small text-ink-dim">
                        {a.before}
                      </p>
                    </div>
                    <div className="mt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        result
                      </p>
                      <p className="mt-1.5 font-display text-[1.375rem] font-semibold leading-snug text-ink">
                        <Figure value={a.result} />
                      </p>
                    </div>
                    <div className="mt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        after
                      </p>
                      <p className="mt-1.5 font-body text-small text-ink-dim">
                        {a.after}
                      </p>
                    </div>
                  </InkReveal>
                ))}
              </ul>
            </ParallaxLayer>
          ))}
        </div>
      </div>
    </Section>
  );
}

/**
 * W1 — Case studies (Work). The 2 CASE_STUDIES travel LEFT as full-width
 * chapters on an AxisRail (pinned horizontal scrub — the primitive owns the
 * scar-#5 fling latch, the scar-#4 relative root and the scar-#8 static
 * vertical stack for reduced/mobile). Each chapter pairs the case file
 * (title + description, locked concepts/figures from src/data/caseStudies.js)
 * with a drafted metric sheet: the before-state struck through, the headline
 * figure CountStriking when the chapter centers (final number renders
 * immediately on the static tier), and the agents roster as mono trace rows.
 *
 * QA hook: the rail root carries id="case-rail" — verify.mjs scrolls through
 * the pin, asserts horizontal travel, and asserts data-latched="end" after a
 * fling (scar #5).
 */
import { CASE_STUDIES } from "../../data/caseStudies.js";
import {
  Section,
  SectionHeader,
  AxisRail,
  CountStrike,
} from "../../components/motion/index.js";

// Per-case metric sheet (free copy — the LOCKED figures already live verbatim
// in the data description; the strike re-states them as the panel's number).
// Index-aligned with CASE_STUDIES. `to` omitted ⇒ the agents count is the
// figure (data-driven, never hand-typed).
const METRICS = [
  {
    label: "first draft, turned around",
    before: "4-6 hours · a junior associate",
    to: 10,
    prefix: "under ",
    suffix: " minutes",
  },
  {
    label: "a data team, replaced",
    before: "hire an analyst · learn a dashboard",
    prefix: "",
    suffix: " agents, plain language",
  },
];

export default function CaseStudiesRail() {
  return (
    <Section id="case-studies" bordered>
      <SectionHeader
        eyebrow="Proof, not pitch"
        title="Case files."
        lead="Two agentic systems drawn from real workflows and inked into production. Scroll — the chapters travel sideways."
      />
      <AxisRail id="case-rail" className="mt-10">
        {CASE_STUDIES.map((c, i) => {
          const m = METRICS[i];
          const agents = c.agents.replace(/\.\s*$/, "").split(", ");
          return (
            <article
              key={c.title}
              className="grid content-center gap-10 px-3 pb-12 pt-16 lg:min-h-[70vh] lg:grid-cols-[1.15fr_0.85fr] lg:items-center"
            >
              <div>
                <p className="font-mono text-mono-label uppercase text-muted">
                  <span className="text-accent" aria-hidden="true">
                    —{" "}
                  </span>
                  case file {String(i + 1).padStart(2, "0")}
                </p>
                <h3 className="mt-5 max-w-2xl font-display text-[clamp(1.75rem,3.4vw,3rem)] font-semibold leading-[1.08] tracking-[-0.015em] text-ink">
                  {c.title}
                </h3>
                <p className="mt-5 max-w-xl font-body text-ink-dim">
                  {c.description}
                </p>
              </div>
              <div className="rounded-md border border-line bg-surface p-7">
                <p className="font-mono text-mono-label uppercase text-muted">
                  {m.label}
                </p>
                <p className="mt-3 font-mono text-mono-trace text-muted line-through">
                  {m.before}
                </p>
                <p className="mt-2 font-display text-[clamp(1.5rem,2.4vw,2.25rem)] font-semibold leading-tight text-ink">
                  <CountStrike
                    to={m.to ?? agents.length}
                    prefix={m.prefix}
                    suffix={m.suffix}
                  />
                </p>
                <div className="mt-6 border-t border-line pt-5">
                  <p className="font-mono text-mono-label uppercase text-muted">
                    agents on the case
                  </p>
                  <ul className="mt-3 space-y-1.5">
                    {agents.map((a, k) => (
                      <li key={a} className="font-mono text-mono-trace text-ink-dim">
                        <span className="text-muted">
                          {String(k + 1).padStart(2, "0")} ·
                        </span>{" "}
                        {a}
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            </article>
          );
        })}
      </AxisRail>
    </Section>
  );
}

